#### 2. Server-side binding check utility

**File**: `apps/app/src/lib/github-binding.ts` (NEW)

Cached server-side query (deduplicates within a single request via React `cache`):

```typescript
import { db, githubOrgBindings } from "@db/app";
import { eq } from "@vendor/db";
import { cache } from "react";

export const getGitHubBinding = cache(async (clerkOrgId: string) => {
  const rows = await db
    .select({
      id: githubOrgBindings.id,
      status: githubOrgBindings.status,
      githubOrgLogin: githubOrgBindings.githubOrgLogin,
      githubOrgAvatarUrl: githubOrgBindings.githubOrgAvatarUrl,
    })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.clerkOrgId, clerkOrgId))
    .limit(1);
  return rows[0] ?? null;
});
```

#### 3. Binding check in org layout

**File**: `apps/app/src/app/(app)/(org)/[slug]/layout.tsx`

After the `requireOrgAccess(slug)` block succeeds, add the binding check. This requires the org ID, so change the `requireOrgAccess` call to capture the return value:

```typescript
// Replace lines 43-52 with:
let org: { id: string } | null = null;
try {
  const access = await requireOrgAccess(slug);
  org = { id: access.org.id };
} catch (error) {
  log.debug("[org-layout] access denied", { slug, error: parseError(error) });
  notFound();
}

// Check GitHub binding
const binding = await getGitHubBinding(org.id);
if (!binding || binding.status !== "active") {
  return (
    <HydrateClient>
      <GitHubSetupGate orgSlug={slug} />
    </HydrateClient>
  );
}
```

When no active binding, the layout renders `<GitHubSetupGate>` instead of the sidebar shell. No redirect, no separate route — clean conditional render at the layout level.

#### 4. GitHub setup gate component

**File**: `apps/app/src/app/(app)/(org)/[slug]/_components/github-setup-gate.tsx` (NEW)

Client component that prompts the user to connect their GitHub organization:

```typescript
"use client";

import { useOAuthPopup } from "~/hooks/use-oauth-popup";
import { useRouter } from "next/navigation";
import { trpc } from "@repo/app-trpc/client";

interface GitHubSetupGateProps {
  orgSlug: string;
}

export function GitHubSetupGate({ orgSlug }: GitHubSetupGateProps) {
  const router = useRouter();

  const { handleConnect, isConnecting } = useOAuthPopup({
    provider: "github",
    queryKeysToInvalidate: [
      trpc.githubBinding.get.queryKey(),
      trpc.connections.generic.listInstallations.queryKey(),
    ],
    onSuccess: () => {
      // Re-render the server layout — it will now detect the binding
      // and render the full sidebar shell instead of this gate
      router.refresh();
    },
  });

  return (
    <div className="flex h-full items-center justify-center bg-background">
      <div className="flex max-w-md flex-col items-center gap-6 text-center">
        <div className="flex flex-col gap-2">
          <h1 className="text-2xl font-semibold tracking-tight">
            Connect your GitHub organization
          </h1>
          <p className="text-muted-foreground">
            Lightfast requires a GitHub organization to get started.
            Connect yours to begin.
          </p>
        </div>
        <button
          type="button"
          onClick={handleConnect}
          disabled={isConnecting}
          className="inline-flex items-center gap-2 rounded-lg bg-primary px-6 py-3 text-sm font-medium text-primary-foreground hover:bg-primary/90 disabled:opacity-50"
        >
          {isConnecting ? "Connecting..." : "Connect GitHub"}
        </button>
      </div>
    </div>
  );
}
```

After the popup closes successfully, `router.refresh()` triggers a server-side re-render. The layout re-queries `getGitHubBinding`, finds the active binding, and renders the normal sidebar shell.

#### 5. Update org creation navigation

**File**: `apps/app/src/app/(app)/(user)/(pending-allowed)/account/teams/new/_components/team-name-form.tsx`

In the `onSuccess` callback (around line 39), change the navigation target:

