"use client";

import { useSearchParams } from "next/navigation";
import { useEffect } from "react";

const MESSAGES: Record<string, string> = {
  github_org_bound_to_other:
    "This GitHub organization is already connected to another Lightfast team.",
  org_already_bound:
    "This team is already connected to a different GitHub organization.",
};

export default function GitHubErrorPage() {
  const searchParams = useSearchParams();
  const reason = searchParams.get("error") ?? "unknown";
  const message = MESSAGES[reason] ?? `Connection failed: ${reason}`;

  useEffect(() => {
    // Signal the opener that connection failed
    try {
      const bc = new BroadcastChannel("oauth-connections");
      bc.postMessage({ type: "github_error", reason });
      bc.close();
    } catch {}
