        <div style={{ fontSize: 48, marginBottom: 16 }}>&#10007;</div>
        <h1 style={{ margin: "0 0 8px" }}>Connection Failed</h1>
        <p style={{ color: "#666" }}>{message}</p>
        <button
          type="button"
          onClick={() => window.close()}
