### Pattern 7: `orgScopedProcedure` Definition
**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/api/app/src/trpc.ts:234-260`

```ts
export const orgScopedProcedure = t.procedure
  .use(observabilityMiddleware)
  .use(({ ctx, next }) => {
    if (ctx.auth.type === "unauthenticated") {
      throw new TRPCError({ code: "UNAUTHORIZED", message: "..." });
    }
    if (ctx.auth.type !== "clerk-active") {
      throw new TRPCError({ code: "FORBIDDEN", message: "Organization required..." });
    }
    return next({
      ctx: {
        ...ctx,
        auth: ctx.auth as Extract<AuthContext, { type: "clerk-active" }>,
      },
    });
  });
```

