### Pattern 12: BroadcastChannel — Opener Side (Hook)
**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/app/src/hooks/use-oauth-popup.ts:69-99`

```ts
useEffect(() => {
  const channel = new BroadcastChannel("oauth-connections");
  channel.onmessage = (event: MessageEvent) => {
    if ((event.data as { type?: string }).type === resolvedMessageType) {
      invalidateAll();
    }
  };

  // postMessage fallback
  const handler = (event: MessageEvent) => {
    if (event.origin !== window.location.origin) return;
    if ((event.data as { type?: string }).type === resolvedMessageType) {
      invalidateAll();
    }
  };
  window.addEventListener("message", handler);

  return () => {
    channel.close();
    window.removeEventListener("message", handler);
  };
}, [invalidateAll, resolvedMessageType]);
```

`resolvedMessageType` defaults to `"${provider}_connected"` if `messageType` prop is not supplied.

