### Pattern 13: `buildRedirectForError` in OAuth Callback
**Found in**: `/Users/jeevanpillay/Code/@lightfastai/lightfast/api/platform/src/lib/oauth/callback.ts:117-139`

```ts
function buildRedirectForError(
  stateData: Record<string, string>,
  providerName: SourceType,
  message: string
): CallbackProcessResult {
  const redirectTo = stateData.redirectTo;

  if (redirectTo === "inline") {
    return { kind: "inline_html", html: errorHtml(message), status: 400 };
  }

  if (redirectTo) {
    return {
      kind: "redirect",
      url: `${redirectTo}?error=${encodeURIComponent(message)}`,
    };
  }

  // Default: redirect to /provider/<provider>/connected?error=...
  return {
    kind: "redirect",
    url: `${appUrl}/provider/${providerName}/connected?error=${encodeURIComponent(message)}`,
  };
}
```

The structured `CallbackProcessResult` discriminated union (`"redirect" | "inline_html" | "error"`) is defined at `/Users/jeevanpillay/Code/@lightfastai/lightfast/api/platform/src/lib/oauth/callback.ts:45-48` and the route handler at `/Users/jeevanpillay/Code/@lightfastai/lightfast/apps/platform/src/app/api/connect/[provider]/callback/route.ts:41-68` maps it to HTTP responses via a `switch` on `result.kind`.

