#### 4. BroadcastChannel error signaling for binding rejection

**No new error page needed.** `buildRedirectForError` already redirects to `/provider/github/connected?error=...`. The existing connected page at `apps/app/src/app/(providers)/provider/github/connected/page.tsx` needs to detect the `?error=` param and broadcast a different message type so the setup gate can show an inline error.

**File**: `apps/app/src/app/(providers)/provider/github/connected/page.tsx`

Update the `useEffect` to check for `?error=` and broadcast accordingly:

```typescript
"use client";

import { useSearchParams } from "next/navigation";
import { useEffect } from "react";

export default function GitHubConnectedPage() {
  const searchParams = useSearchParams();
  const error = searchParams.get("error");

  useEffect(() => {
    const channel = new BroadcastChannel("oauth-connections");

    if (error) {
      // Binding rejected — signal error to opener
      channel.postMessage({ type: "github_error", reason: error });
    } else {
      // Success — signal connection complete
      channel.postMessage({ type: "github_connected" });
    }
    channel.close();

    // Fallback: window.opener.postMessage
    const opener = window.opener as Window | null;
    if (opener) {
      try {
        opener.postMessage(
          error
            ? { type: "github_error", reason: error }
            : { type: "github_connected" },
          window.location.origin
        );
      } catch {}
    }

    const timer = setTimeout(() => window.close(), 2000);
    return () => clearTimeout(timer);
  }, [error]);

  return (
    <div style={{
      fontFamily: "system-ui",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      height: "100vh",
    }}>
      <p>{error ? "Connection failed. This window will close." : "Connected! This window will close."}</p>
    </div>
  );
}
```

